def sha256_bytes(b: bytes) -> str:
    h = hashlib.sha256()
    h.update(b)
    return h.hexdigest()


def safe_ext_from_mime(mime: Optional[str]) -> str:
    if not mime:
        return ".bin"
    mime = mime.lower().strip()
    if mime in ("image/jpeg", "image/jpg"):
        return ".jpg"
    if mime == "image/png":
        return ".png"
    if mime == "image/webp":
        return ".webp"
    if mime == "image/bmp":
        return ".bmp"
    if mime == "image/tiff":
        return ".tif"
    return ".img"


def ensure_image_openable(path: str):
    try:
        with Image.open(path) as im:
            im.verify()
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid or corrupted image")


