@app.post("/images/upload", response_model=UploadImageResponse, dependencies=[Depends(require_api_key)])
async def upload_image(file: UploadFile = File(...)):
    b = await file.read()
    if not b:
        raise HTTPException(status_code=400, detail="Empty file")
    digest = sha256_bytes(b)
    ext = safe_ext_from_mime(file.content_type)
    image_id = str(uuid.uuid4())
    filename = f"{image_id}{ext}"
    path = os.path.join(IMAGES_DIR, filename)

    with _db_lock:
        con = _conn()
        cur = con.cursor()
        cur.execute("SELECT id, filename FROM images WHERE sha256 = ?", (digest,))
        row = cur.fetchone()
        if row:
            con.close()
            return UploadImageResponse(image_id=row["id"], filename=row["filename"], sha256=digest)

        with open(path, "wb") as f:
            f.write(b)

        ensure_image_openable(path)

        cur.execute(
            "INSERT INTO images (id, filename, sha256, mime, created_at) VALUES (?, ?, ?, ?, ?)",
            (image_id, filename, digest, file.content_type, _now()),
        )
        con.commit()
        con.close()

    return UploadImageResponse(image_id=image_id, filename=filename, sha256=digest)


