@app.post("/labels/submit", response_model=SubmitLabelResponse, dependencies=[Depends(require_api_key)])
def submit_label(req: SubmitLabelRequest):
    if not req.label or not req.label.strip():
        raise HTTPException(status_code=400, detail="Label required")
    if not req.annotator_id or not req.annotator_id.strip():
        raise HTTPException(status_code=400, detail="annotator_id required")

    label_id = str(uuid.uuid4())
    with _db_lock:
        con = _conn()
        cur = con.cursor()
        cur.execute("SELECT 1 FROM images WHERE id = ?", (req.image_id,))
        if not cur.fetchone():
            con.close()
