def _aggregate_counts(image_id: str) -> Dict[str, int]:
    with _db_lock:
        con = _conn()
        cur = con.cursor()
        cur.execute("SELECT label, COUNT(1) AS c FROM labels WHERE image_id=? GROUP BY label", (image_id,))
        rows = cur.fetchall()
        con.close()
    return {r["label"]: int(r["c"]) for r in rows}


def _majority_vote(counts: Dict[str, int]) -> Optional[str]:
    if not counts:
        return None
    max_c = max(counts.values())
    winners = sorted([k for k, v in counts.items() if v == max_c])
    return winners[0] if winners else None


