class SimpleImageDataset(Dataset):
    def __init__(self, samples: List[Tuple[str, int]], image_size: int):
        self.samples = samples
        self.image_size = image_size

    def __len__(self):
        return len(self.samples)

    def _load_tensor(self, path: str) -> torch.Tensor:
        with Image.open(path) as im:
            im = im.convert("RGB")
            im = im.resize((self.image_size, self.image_size))
            t = torch.from_numpy(__import__("numpy").array(im)).float() / 255.0
            t = t.permute(2, 0, 1).contiguous()
            return t

    def __getitem__(self, idx: int):
        path, y = self.samples[idx]
        x = self._load_tensor(path)
        return x, torch.tensor(y, dtype=torch.long)


class TinyCNN(nn.Module):
    def __init__(self, num_classes: int):
        super().__init__()
        self.features = nn.Sequential(
            nn.Conv2d(3, 32, 3, padding=1),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(2),
            nn.Conv2d(32, 64, 3, padding=1),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(2),
            nn.Conv2d(64, 128, 3, padding=1),
            nn.ReLU(inplace=True),
            nn.AdaptiveAvgPool2d((1, 1)),
        )
        self.classifier = nn.Sequential(
            nn.Flatten(),
            nn.Linear(128, num_classes),
        )

    def forward(self, x):
        x = self.features(x)
        x = self.classifier(x)
        return x


def _build_training_set(min_votes: int, max_images: Optional[int]) -> Tuple[List[Tuple[str, str]], Dict[str, Any]]:
    with _db_lock:
        con = _conn()
        cur = con.cursor()
        cur.execute("SELECT id, filename FROM images ORDER BY created_at DESC")
        images = cur.fetchall()
        con.close()

    samples: List[Tuple[str, str]] = []
    skipped_missing = 0
    skipped_votes = 0
    for r in images:
        image_id = r["id"]
        filename = r["filename"]
        path = os.path.join(IMAGES_DIR, filename)
        if not os.path.exists(path):
            skipped_missing += 1
            continue
        counts = _aggregate_counts(image_id)
        total = int(sum(counts.values()))
        if total < min_votes:
            skipped_votes += 1
            continue
        agg = _majority_vote(counts)
        if agg is None:
            skipped_votes += 1
            continue
        samples.append((path, agg))
        if max_images is not None and len(samples) >= max_images:
            break

    meta = {
        "num_images_total": len(images),
        "num_samples": len(samples),
        "skipped_missing": skipped_missing,
        "skipped_low_votes": skipped_votes,
    }
    return samples, meta


def _train_job(model_id: str, params: TrainRequest):
    with _db_lock:
        con = _conn()
        cur = con.cursor()
        cur.execute("UPDATE models SET status=?, detail=? WHERE id=?", ("running", None, model_id))
        con.commit()
        con.close()

    try:
        samples, meta = _build_training_set(params.min_votes, params.max_images)
        if not samples:
            raise RuntimeError("No aggregated labeled samples available for training")

        labels = sorted(list({lab for _, lab in samples}))
        label_to_idx = {lab: i for i, lab in enumerate(labels)}
        idx_to_label = {str(i): lab for lab, i in label_to_idx.items()}

        samples_idx = [(p, label_to_idx[lab]) for p, lab in samples]

        device = params.device or ("cuda" if torch.cuda.is_available() else "cpu")
        image_size = int(params.image_size)
        epochs = max(1, int(params.epochs))
        batch_size = max(1, int(params.batch_size))
        lr = float(params.lr)

        ds = SimpleImageDataset(samples_idx, image_size=image_size)
        dl = DataLoader(ds, batch_size=batch_size, shuffle=True, num_workers=0, pin_memory=(device == "cuda"))

        model = TinyCNN(num_classes=len(labels)).to(device)
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(model.parameters(), lr=lr)

        model.train()
        for _ in range(epochs):
            for x, y in dl:
                x = x.to(device, non_blocking=True)
                y = y.to(device, non_blocking=True)
                optimizer.zero_grad(set_to_none=True)
                logits = model(x)
                loss = criterion(logits, y)
                loss.backward()
                optimizer.step()

        tmp_dir = os.path.join(MODEL_DIR, f"tmp_{model_id}")
        os.makedirs(tmp_dir, exist_ok=True)
        tmp_model_path = os.path.join(tmp_dir, "model.pt")
        tmp_label_map_path = os.path.join(tmp_dir, "label_map.json")

        torch.save(
            {
                "model_state_dict": model.state_dict(),
                "num_classes": len(labels),
                "image_size": image_size,
                "label_to_idx": label_to_idx,
                "created_at": _now(),
            },
            tmp_model_path,
        )
        with open(tmp_label_map_path, "w", encoding="utf-8") as f:
            json.dump({"label_to_idx": label_to_idx, "idx_to_label": idx_to_label}, f, ensure_ascii=False, indent=2)

        os.replace(tmp_model_path, MODEL_PATH)
        os.replace(tmp_label_map_path, LABEL_MAP_PATH)
        shutil.rmtree(tmp_dir, ignore_errors=True)

        with _db_lock:
            con = _conn()
            cur = con.cursor()
            cur.execute(
                """
                UPDATE models
                SET status=?, detail=?, model_path=?, label_map_path=?, num_images=?, num_labels=?, num_classes=?
                WHERE id=?
                """,
                (
                    "completed",
                    json.dumps(meta),
                    MODEL_PATH,
                    LABEL_MAP_PATH,
                    len(samples),
                    len(samples),
                    len(labels),
                    model_id,
                ),
            )
            con.commit()
            con.close()
    except Exception as e:
        with _db_lock:
            con = _conn()
            cur = con.cursor()
            cur.execute("UPDATE models SET status=?, detail=? WHERE id=?", ("failed", str(e), model_id))
            con.commit()
            con.close()


@app.post("/train", response_model=TrainResponse, dependencies=[Depends(require_api_key)])
def train(req: TrainRequest):
    model_id = str(uuid.uuid4())
    with _db_lock:
        con = _conn()
        cur = con.cursor()
        cur.execute(
            "INSERT INTO models (id, created_at, status, detail) VALUES (?, ?, ?, ?)",
            (model_id, _now(), "queued", None),
        )
        con.commit()
        con.close()

    t = threading.Thread(target=_train_job, args=(model_id, req), daemon=True)
    t.start()

    return TrainResponse(model_id=model_id, status="queued", detail=None)


