class PredictRequest(BaseModel):
    image_id: str


@app.post("/predict", dependencies=[Depends(require_api_key)])
def predict(req: PredictRequest):
    if not os.path.exists(MODEL_PATH) or not os.path.exists(LABEL_MAP_PATH):
        raise HTTPException(status_code=404, detail="No trained model available")

    with _db_lock:
        con = _conn()
        cur = con.cursor()
        cur.execute("SELECT filename FROM images WHERE id=?", (req.image_id,))
        row = cur.fetchone()
        con.close()
    if not row:
        raise HTTPException(status_code=404, detail="Image not found")

    img_path = os.path.join(IMAGES_DIR, row["filename"])
    if not os.path.exists(img_path):
        raise HTTPException(status_code=404, detail="File missing")

    with open(LABEL_MAP_PATH, "r", encoding="utf-8") as f:
        lm = json.load(f)
    idx_to_label = lm.get("idx_to_label", {})

    ckpt = torch.load(MODEL_PATH, map_location="cpu")
    image_size = int(ckpt.get("image_size", 128))
    num_classes = int(ckpt.get("num_classes", 0))
    if num_classes <= 0:
        raise HTTPException(status_code=500, detail="Invalid model checkpoint")

    model = TinyCNN(num_classes=num_classes)
    model.load_state_dict(ckpt["model_state_dict"])
    model.eval()

    with Image.open(img_path) as im:
        im = im.convert("RGB")
        im = im.resize((image_size, image_size))
        import numpy as np
        x = torch.from_numpy(np.array(im)).float() / 255.0
        x = x.permute(2, 0, 1).unsqueeze(0)

    with torch.no_grad():
        logits = model(x)
        probs = torch.softmax(logits, dim=1)[0]
        top_prob, top_idx = torch.max(probs, dim=0)
        pred_label = idx_to_label.get(str(int(top_idx.item())), None)

    return {
        "image_id": req.image_id,
        "predicted_label": pred_label,
        "confidence": float(top_prob.item()),
        "num_classes": num_classes,
    }


